// 1. 取得 Loop 傳過來的「個人目標」(TDEE)
// 注意：要往回找 Loop 節點的資料，因為 Sheets 節點只會有飲食資料
const userProfile = $('Loop Over Items').item.json;
const tdee = parseFloat(userProfile['TDEE目標 ']) || 2000;

// 2. 取得 Google Sheets 撈出來的「今日飲食」
const foodRecords = $input.all();

// 3. 開始加總
let totalCal = 0;
let foodList = [];

// 如果沒吃到東西 (空陣列)，totalCal 就是 0
if (foodRecords.length > 0 && foodRecords[0].json['食物名稱']) {
    foodRecords.forEach(item => {
        totalCal += parseFloat(item.json['估算熱量(kcal)']) || 0;
        foodList.push(item.json['食物名稱']);
    });
}

// 4. 計算狀態
let diff = totalCal - tdee;
let status = "";
if (totalCal === 0) status = "未紀錄";
else if (diff > 200) status = "🔴 爆量";
else if (diff < -500) status = "🟡 吃太少";
else status = "🟢 完美達標";

return {
    userId: userProfile.userId, // 記住 ID 才能推播
    tdee: tdee,
    totalCal: totalCal,
    foodItems: foodList.join(", "),
    diff: diff,
    status: status
};

